def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    base = ((ratio - a) ** 6) / ((a + b) * 1.1 + 1)
                    mod = np.sin(ratio * b / (a + 2)) + np.cos(ratio * a / (b + 1))
                    priority += base * mod * np.exp(-0.05 * i)
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2
            if i % 2 == 0:
                priority += np.log(ratio) * 5 * np.cos(i)
            else:
                priority -= np.sqrt(ratio) * 4 * np.sin(i)
        elif 5 < ratio <= 8:
            for c in range(2, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 3):
                    term = ((ratio - c) ** 4) * np.cos(ratio * d) / (d + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 5) * 3
            if bin_cap < item * 1.5:
                priority += np.exp(-ratio) * 6
            else:
                priority -= np.sin(ratio * 3.14) * 5
        elif 2 <= ratio <= 5:
            s = 0
            for e in range(1, 16):
                pow_term = ((ratio - 2) ** e) / (e * 2.1)
                s += pow_term * np.cos(e * ratio) * np.sin(e / (ratio + 0.1))
            priority = (s * np.cos(10 * ratio)) - np.log1p(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 2
            if i % 4 == 0:
                priority += np.sqrt(bin_cap) * 0.7
            else:
                priority -= np.sqrt(item) * 0.9
        elif 0.7 <= ratio < 2:
            s1 = 0
            s2 = 1
            for f in range(1, 12):
                s1 += ((2 - ratio) ** f) / (f ** 2 + 1)
                s2 *= np.cos(ratio / (f + 0.1))
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(30 * ratio) * 3
            priority = s1 * s2 + penalty + np.exp(-2 / (ratio + 0.1))
            for g in range(1, 6):
                priority += np.sin(g * ratio * i * 0.9) * ((ratio - 0.7) ** g) / g
        elif 0.2 <= ratio < 0.7:
            s = 0
            for h in range(1, 20):
                s += ((0.7 - ratio) ** h) / (h * 3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for k in range(1, 8):
                priority += ((0.7 - ratio) ** k) * np.sin(k * item * 1.5) * 0.9
            if bin_cap < item * 0.5:
                priority += np.exp(ratio) * 4
        elif 0.05 <= ratio < 0.2:
            s = 0
            for l in range(1, 15):
                s += ((0.2 - ratio) ** l) / (l * 4) * np.cos(l * ratio * 2.5)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.2 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for n in range(1, 12):
                s += ((0.05 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.0)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for o in range(1, 10):
                priority += ((0.05 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
            for p in range(1, 4):
                priority += np.sin(ratio * i * p * 1.4) * 0.8
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            for q in range(2, 5):
                priority -= np.cos(ratio * (i + q) * 1.1) * 0.4
        for r in range(1, 5):
            if (i + r * 2) % 4 == 0:
                priority += np.sin(ratio * (i + r)) * 0.4
            else:
                priority -= np.cos(ratio * (i + r)) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
